func TestClampChartSigFigs(t *testing.T) {
	tests := []struct {
		name     string
		frontend Frontend
		want     int
	}{
		{name: "defaults zero", frontend: Frontend{}, want: 4},
		{
			name: "clamps low",
			frontend: Frontend{
				Charts: FrontendCharts{SigFigs: 1},
			},
			want: 2,
		},
		{
			name: "clamps high",
			frontend: Frontend{
				Charts: FrontendCharts{SigFigs: 99},
			},
