package analytics

import (
	"context"
	"errors"

	marketmath "socialpredict/internal/domain/math/market"
)

// DebtStats represents aggregated debt metrics.
type DebtStats struct {
	UserCount         int64
	UnusedDebt        int64
	RealizedProfits   int64
	TotalDebtCapacity int64
}

// MarketVolumeStats represents market volume metrics.
type MarketVolumeStats struct {
	MarketCreationFees int64
	ActiveBetVolume    int64
}

// ComputeSystemMetrics aggregates system-wide monetary metrics.
func (s *Service) ComputeSystemMetrics(ctx context.Context) (*SystemMetrics, error) {
	if s.repo == nil {
		return nil, errors.New("repository not provided")
	}

	s.ensureStrategyDefaults()

	debtStats, err := s.debtCalculator.Calculate(ctx, s.repo, s.config)
	if err != nil {
		return nil, err
	}

	volumeStats, err := s.volumeCalculator.Calculate(ctx, s.repo, s.config)
	if err != nil {
		return nil, err
	}

	participationFees, err := s.feeCalculator.CalculateParticipationFees(ctx, s.repo, s.config)
	if err != nil {
		return nil, err
	}

	return s.metricsAssembler.Assemble(debtStats, volumeStats, participationFees), nil
}

// DefaultDebtCalculator implements the existing debt policy.
type DefaultDebtCalculator struct{}

func (c DefaultDebtCalculator) Calculate(ctx context.Context, repo DebtRepository, config Config) (*DebtStats, error) {
	users, err := repo.ListUsers(ctx)
	if err != nil {
		return nil, err
	}

	stats := &DebtStats{
		UserCount: int64(len(users)),
	}

	for _, user := range users {
		balance := user.AccountBalance
		if balance > 0 {
			stats.RealizedProfits += balance
		}
		usedDebt := int64(0)
		if balance < 0 {
			usedDebt = -balance
		}
		stats.UnusedDebt += config.MaximumDebtAllowed - usedDebt
	}

	stats.TotalDebtCapacity = config.MaximumDebtAllowed * stats.UserCount
	return stats, nil
}

// DefaultVolumeCalculator implements the existing volume policy.
type DefaultVolumeCalculator struct{}

func (c DefaultVolumeCalculator) Calculate(ctx context.Context, repo VolumeRepository, config Config) (*MarketVolumeStats, error) {
	markets, err := repo.ListMarkets(ctx)
	if err != nil {
		return nil, err
	}

	stats := &MarketVolumeStats{
		MarketCreationFees: int64(len(markets)) * config.CreateMarketCost,
	}

	for _, market := range markets {
		if market.IsResolved {
			continue
		}

		bets, err := repo.ListBetsForMarket(ctx, market.ID)
		if err != nil {
			return nil, err
		}
		stats.ActiveBetVolume += marketmath.GetMarketVolume(bets)
	}

	return stats, nil
}

// DefaultFeeCalculator implements the existing participation fee policy.
type DefaultFeeCalculator struct{}

func (c DefaultFeeCalculator) CalculateParticipationFees(ctx context.Context, repo FeeRepository, config Config) (int64, error) {
	betsOrdered, err := repo.ListBetsOrdered(ctx)
	if err != nil {
		return 0, err
	}

	type userMarket struct {
		marketID uint
		username string
	}

	seen := make(map[userMarket]bool)
	var participationFees int64

	for _, b := range betsOrdered {
		if b.Amount <= 0 {
			continue
		}
		key := userMarket{marketID: b.MarketID, username: b.Username}
		if !seen[key] {
			participationFees += config.InitialBetFee
			seen[key] = true
		}
	}

	return participationFees, nil
}

// DefaultMetricsAssembler builds the SystemMetrics DTO from calculator outputs.
type DefaultMetricsAssembler struct{}

func (a DefaultMetricsAssembler) Assemble(debt *DebtStats, volume *MarketVolumeStats, participationFees int64) *SystemMetrics {
	bonusesPaid := debt.RealizedProfits
	totalUtilized := debt.UnusedDebt + volume.ActiveBetVolume + volume.MarketCreationFees + participationFees + bonusesPaid
	surplus := debt.TotalDebtCapacity - totalUtilized
	balanced := surplus == 0

	return &SystemMetrics{
		MoneyCreated: MoneyCreated{
			UserDebtCapacity: NewInt64Metric(debt.TotalDebtCapacity, "numUsers × maxDebtPerUser", "Total credit capacity made available to all users"),
			NumUsers:         NewInt64Metric(debt.UserCount, "", "Total number of registered users"),
		},
		MoneyUtilized: MoneyUtilized{
			UnusedDebt:         NewInt64Metric(debt.UnusedDebt, "Σ(maxDebtPerUser - max(0, -balance))", "Remaining borrowing capacity available to users"),
			ActiveBetVolume:    NewInt64Metric(volume.ActiveBetVolume, "Σ(unresolved_market_volumes)", "Total value of bets currently active in unresolved markets (excludes fees and subsidies)"),
			MarketCreationFees: NewInt64Metric(volume.MarketCreationFees, "number_of_markets × creation_fee_per_market", "Fees collected from users creating new markets"),
			ParticipationFees:  NewInt64Metric(participationFees, "Σ(first_bet_per_user_per_market × participation_fee)", "Fees collected from first-time participation in each market"),
			BonusesPaid:        NewInt64Metric(bonusesPaid, "", "System bonuses paid to users and realized profits currently held in user balances"),
			TotalUtilized:      NewInt64Metric(totalUtilized, "unusedDebt + activeBetVolume + marketCreationFees + participationFees + bonusesPaid", "Total debt capacity that has been utilized across all categories"),
		},
		Verification: Verification{
			Balanced: NewBoolMetric(balanced, "Whether total created equals total utilized (perfect accounting balance)"),
			Surplus:  NewInt64Metric(surplus, "userDebtCapacity - totalUtilized", "Positive = unused capacity, Negative = over-utilization (indicates accounting error)"),
		},
	}
}

package bets

import (
	"context"
	"time"

	"socialpredict/internal/domain/boundary"
	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
)

// Repository exposes the persistence layer needed by the bets domain service.
type BetWriter interface {
	Create(ctx context.Context, bet *boundary.Bet) error
}

// BetHistoryReader exposes prior-participation lookups used for buy fee rules.
type BetHistoryReader interface {
	UserHasBet(ctx context.Context, marketID uint, username string) (bool, error)
}

// Repository exposes the persistence layer needed by the bets domain service.
type Repository interface {
	BetWriter
	BetHistoryReader
}

// MarketService exposes the subset of market operations required by bets.
type MarketReader interface {
	GetMarket(ctx context.Context, id int64) (*dmarkets.Market, error)
}

// PositionReader exposes the position reads needed by share-sale flows.
type PositionReader interface {
	GetUserPositionInMarket(ctx context.Context, marketID int64, username string) (*dmarkets.UserPosition, error)
}

// MarketService exposes the subset of market operations required by bets.
type MarketService interface {
	MarketReader
	PositionReader
}

// MarketGate ensures market openness before betting operations.
type MarketGate interface {
	Open(ctx context.Context, marketID int64) (*dmarkets.Market, error)
}

// UserService exposes the subset of user operations required by bets.
type UserReader interface {
	GetUser(ctx context.Context, username string) (*dusers.User, error)
}

// TransactionRecorder exposes account mutations used by the betting ledger.
type TransactionRecorder interface {
	ApplyTransaction(ctx context.Context, username string, amount int64, transactionType string) error
}

// UserService exposes the subset of user operations required by bets.
type UserService interface {
	UserReader
	TransactionRecorder
}

// PlaceValidator allows validation rules to be extended without changing the service.
type PlaceValidator interface {
	Validate(ctx context.Context, req PlaceRequest) (string, error)
}

// SellValidator allows sell validation rules to be extended without changing the service.
type SellValidator interface {
	Validate(ctx context.Context, req SellRequest) (string, error)
}

// SaleCalculator encapsulates sale pricing and dust rules.
type SaleCalculator interface {
	Calculate(pos *dmarkets.UserPosition, sharesOwned int64, creditsRequested int64) (SaleQuote, error)
}

// FeeCalculator encapsulates buy fee calculations.
type FeeCalculator interface {
	Calculate(hasBet bool, amount int64) betFees
}

// BalanceGuard validates user balances against debt limits.
type BalanceGuard interface {
	EnsureSufficient(balance, totalCost int64) error
}

// BetLedger encapsulates persistence and user accounting for bets.
type BetLedger interface {
	ChargeAndRecord(ctx context.Context, bet *boundary.Bet, totalCost int64) error
	CreditSale(ctx context.Context, bet *boundary.Bet, saleValue int64) error
}

// Clock allows time to be mocked in tests.
type Clock interface {
	Now() time.Time
}

// Config holds the narrow economics policy slice required by the bets domain.
type Config struct {
	InitialBetFee      int64
	BuySharesFee       int64
	MaxDustPerSale     int64
	MaximumDebtAllowed int64
}

type serviceClock struct{}

func (serviceClock) Now() time.Time { return time.Now() }

// ServiceInterface defines the behaviour offered by the bets domain.
type ServiceInterface interface {
	Place(ctx context.Context, req PlaceRequest) (*PlacedBet, error)
	Sell(ctx context.Context, req SellRequest) (*SellResult, error)
}

// Service implements the bets domain logic.
type Service struct {
	repo    Repository
	markets MarketService
	users   UserService
	config  Config
	clock   Clock

	placeValidator PlaceValidator
	sellValidator  SellValidator

	marketGate     MarketGate
	fees           FeeCalculator
	balances       BalanceGuard
	ledger         BetLedger
	saleCalculator SaleCalculator
}

var (
	_ ServiceInterface = (*Service)(nil)
	_ SaleCalculator   = saleCalculator{}
)

// ServiceOption configures bets Service collaborators.
type ServiceOption func(*Service)

func defaultClock() Clock {
	return serviceClock{}
}

func defaultPlaceValidatorStrategy() PlaceValidator {
	return defaultPlaceValidator{}
}

func defaultSellValidatorStrategy() SellValidator {
	return defaultSellValidator{}
}

func defaultMarketGateStrategy(markets MarketReader, clock Clock) MarketGate {
	return marketGate{markets: markets, clock: clock}
}

func defaultFeeCalculatorStrategy(config Config) FeeCalculator {
	return feeCalculator{config: config}
}

func defaultBalanceGuardStrategy(config Config) BalanceGuard {
	return balanceGuard{maxDebtAllowed: config.MaximumDebtAllowed}
}

func defaultBetLedgerStrategy(repo BetWriter, users TransactionRecorder) BetLedger {
	return betLedger{repo: repo, users: users}
}

func defaultSaleCalculatorStrategy(config Config) SaleCalculator {
	return saleCalculator{maxDustPerSale: config.MaxDustPerSale}
}

func clockOrDefault(clock Clock) Clock {
	if clock == nil {
		return defaultClock()
	}
	return clock
}

func placeValidatorOrDefault(v PlaceValidator) PlaceValidator {
	if v == nil {
		return defaultPlaceValidatorStrategy()
	}
	return v
}

func sellValidatorOrDefault(v SellValidator) SellValidator {
	if v == nil {
		return defaultSellValidatorStrategy()
	}
	return v
}

func marketGateOrDefault(g MarketGate, markets MarketReader, clock Clock) MarketGate {
	if g == nil {
		return defaultMarketGateStrategy(markets, clock)
	}
	return g
}

func feeCalculatorOrDefault(c FeeCalculator, config Config) FeeCalculator {
	if c == nil {
		return defaultFeeCalculatorStrategy(config)
	}
	return c
}

func balanceGuardOrDefault(g BalanceGuard, config Config) BalanceGuard {
	if g == nil {
		return defaultBalanceGuardStrategy(config)
	}
	return g
}

func betLedgerOrDefault(l BetLedger, repo BetWriter, users TransactionRecorder) BetLedger {
	if l == nil {
		return defaultBetLedgerStrategy(repo, users)
	}
	return l
}

func saleCalculatorOrDefault(c SaleCalculator, config Config) SaleCalculator {
	if c == nil {
		return defaultSaleCalculatorStrategy(config)
	}
	return c
}

// WithPlaceValidator overrides the place validator.
func WithPlaceValidator(v PlaceValidator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.placeValidator = placeValidatorOrDefault(v)
		}
	}
}

// WithSellValidator overrides the sell validator.
func WithSellValidator(v SellValidator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.sellValidator = sellValidatorOrDefault(v)
		}
	}
}

// WithMarketGate overrides the market gate.
func WithMarketGate(g MarketGate) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.marketGate = marketGateOrDefault(g, s.markets, clockOrDefault(s.clock))
		}
	}
}

