package config

import (
	"errors"
	"testing"

	"socialpredict/setup"
)

func TestNewServiceLoadsCurrentConfig(t *testing.T) {
	cfg := &AppConfig{
		Economics: Economics{
			User: User{MaximumDebtAllowed: 500},
		},
		Frontend: Frontend{
			Charts: FrontendCharts{SigFigs: 7},
		},
	}

	svc, err := NewService(LoaderFunc(func() (*AppConfig, error) {
		return cfg, nil
	}))
	if err != nil {
		t.Fatalf("NewService returned error: %v", err)
	}

	if got := svc.Current(); got != cfg {
		t.Fatalf("Current returned unexpected config pointer")
	}
	if got := svc.Economics().User.MaximumDebtAllowed; got != 500 {
		t.Fatalf("Economics returned wrong maximum debt: got %d", got)
	}
	if got := svc.ChartSigFigs(); got != 7 {
		t.Fatalf("ChartSigFigs returned %d, want 7", got)
	}
}

func TestNewServicePropagatesLoaderError(t *testing.T) {
	wantErr := errors.New("boom")

	svc, err := NewService(LoaderFunc(func() (*AppConfig, error) {
		return nil, wantErr
	}))
	if !errors.Is(err, wantErr) {
		t.Fatalf("NewService error = %v, want %v", err, wantErr)
	}
	if svc != nil {
		t.Fatalf("expected nil service on loader error")
	}
}

func TestClampChartSigFigs(t *testing.T) {
	tests := []struct {
		name     string
		frontend Frontend
		want     int
	}{
		{name: "defaults zero", frontend: Frontend{}, want: 4},
		{
			name: "clamps low",
			frontend: Frontend{
				Charts: FrontendCharts{SigFigs: 1},
			},
			want: 2,
		},
		{
			name: "clamps high",
			frontend: Frontend{
				Charts: FrontendCharts{SigFigs: 99},
			},
			want: 9,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := ClampChartSigFigs(tt.frontend); got != tt.want {
				t.Fatalf("ClampChartSigFigs() = %d, want %d", got, tt.want)
			}
		})
	}
}

func TestSetupCompatibilityTranslation(t *testing.T) {
	legacy := &setup.EconomicConfig{
		Economics: setup.Economics{
			MarketCreation: setup.MarketCreation{
				InitialMarketProbability:   0.42,
				InitialMarketSubsidization: 250,
				InitialMarketYes:           5,
				InitialMarketNo:            7,
				MinimumFutureHours:         24,
			},
			MarketIncentives: setup.MarketIncentives{
				CreateMarketCost: 15,
				TraderBonus:      20,
			},
			User: setup.User{
				InitialAccountBalance: 900,
				MaximumDebtAllowed:    300,
			},
			Betting: setup.Betting{
				MinimumBet:     10,
				MaxDustPerSale: 3,
				BetFees: setup.BetFees{
					InitialBetFee: 1,
					BuySharesFee:  2,
					SellSharesFee: 4,
				},
			},
		},
		Frontend: setup.Frontend{
			Charts: setup.FrontendCharts{SigFigs: 6},
		},
	}

	owned := FromSetup(legacy)
	if owned.Economics.User.InitialAccountBalance != 900 {
		t.Fatalf("owned initial account balance = %d, want 900", owned.Economics.User.InitialAccountBalance)
	}
	if owned.Frontend.Charts.SigFigs != 6 {
		t.Fatalf("owned sig figs = %d, want 6", owned.Frontend.Charts.SigFigs)
	}

	roundTrip := owned.ToSetup()
	if roundTrip.Economics.MarketIncentives.TraderBonus != 20 {
		t.Fatalf("round trip trader bonus = %d, want 20", roundTrip.Economics.MarketIncentives.TraderBonus)
	}
	if roundTrip.Economics.Betting.BetFees.SellSharesFee != 4 {
		t.Fatalf("round trip sell shares fee = %d, want 4", roundTrip.Economics.Betting.BetFees.SellSharesFee)
	}
}

package config

import "socialpredict/setup"

const (
	minChartSigFigs     = 2
	maxChartSigFigs     = 9
	defaultChartSigFigs = 4
)

type MarketCreation struct {
	InitialMarketProbability   float64 `yaml:"initialMarketProbability" json:"initialMarketProbability"`
	InitialMarketSubsidization int64   `yaml:"initialMarketSubsidization" json:"initialMarketSubsidization"`
	InitialMarketYes           int64   `yaml:"initialMarketYes" json:"initialMarketYes"`
	InitialMarketNo            int64   `yaml:"initialMarketNo" json:"initialMarketNo"`
	MinimumFutureHours         float64 `yaml:"minimumFutureHours" json:"minimumFutureHours"`
}

type MarketIncentives struct {
	CreateMarketCost int64 `yaml:"createMarketCost" json:"createMarketCost"`
	TraderBonus      int64 `yaml:"traderBonus" json:"traderBonus"`
}

type User struct {
	InitialAccountBalance int64 `yaml:"initialAccountBalance" json:"initialAccountBalance"`
	MaximumDebtAllowed    int64 `yaml:"maximumDebtAllowed" json:"maximumDebtAllowed"`
}

type BetFees struct {
	InitialBetFee int64 `yaml:"initialBetFee" json:"initialBetFee"`
	BuySharesFee  int64 `yaml:"buySharesFee" json:"buySharesFee"`
	SellSharesFee int64 `yaml:"sellSharesFee" json:"sellSharesFee"`
}

type Betting struct {
	MinimumBet     int64   `yaml:"minimumBet" json:"minimumBet"`
	MaxDustPerSale int64   `yaml:"maxDustPerSale" json:"maxDustPerSale"`
	BetFees        BetFees `yaml:"betFees" json:"betFees"`
}

type Economics struct {
	MarketCreation   MarketCreation   `yaml:"marketcreation" json:"marketcreation"`
	MarketIncentives MarketIncentives `yaml:"marketincentives" json:"marketincentives"`
	User             User             `yaml:"user" json:"user"`
	Betting          Betting          `yaml:"betting" json:"betting"`
}

type FrontendCharts struct {
	SigFigs int `yaml:"sigFigs" json:"sigFigs"`
}

type Frontend struct {
	Charts FrontendCharts `yaml:"charts" json:"charts"`
}

type AppConfig struct {
	Economics Economics `yaml:"economics" json:"economics"`
	Frontend  Frontend  `yaml:"frontend" json:"frontend"`
}

// FromSetup converts the legacy setup snapshot into the owned config service types.
func FromSetup(cfg *setup.EconomicConfig) *AppConfig {
	if cfg == nil {
		return &AppConfig{}
	}

	return &AppConfig{
		Economics: Economics{
			MarketCreation: MarketCreation{
				InitialMarketProbability:   cfg.Economics.MarketCreation.InitialMarketProbability,
				InitialMarketSubsidization: cfg.Economics.MarketCreation.InitialMarketSubsidization,
				InitialMarketYes:           cfg.Economics.MarketCreation.InitialMarketYes,
				InitialMarketNo:            cfg.Economics.MarketCreation.InitialMarketNo,
				MinimumFutureHours:         cfg.Economics.MarketCreation.MinimumFutureHours,
			},
			MarketIncentives: MarketIncentives{
				CreateMarketCost: cfg.Economics.MarketIncentives.CreateMarketCost,
				TraderBonus:      cfg.Economics.MarketIncentives.TraderBonus,
			},
			User: User{
				InitialAccountBalance: cfg.Economics.User.InitialAccountBalance,
				MaximumDebtAllowed:    cfg.Economics.User.MaximumDebtAllowed,
			},
			Betting: Betting{
				MinimumBet:     cfg.Economics.Betting.MinimumBet,
				MaxDustPerSale: cfg.Economics.Betting.MaxDustPerSale,
				BetFees: BetFees{
					InitialBetFee: cfg.Economics.Betting.BetFees.InitialBetFee,
					BuySharesFee:  cfg.Economics.Betting.BetFees.BuySharesFee,
					SellSharesFee: cfg.Economics.Betting.BetFees.SellSharesFee,
				},
			},
		},
		Frontend: Frontend{
			Charts: FrontendCharts{
				SigFigs: cfg.Frontend.Charts.SigFigs,
			},
		},
	}
}

// ToSetup converts the owned snapshot into the legacy setup shape for unmigrated consumers.
func (cfg *AppConfig) ToSetup() *setup.EconomicConfig {
	if cfg == nil {
		return &setup.EconomicConfig{}
	}

	return &setup.EconomicConfig{
		Economics: setup.Economics{
			MarketCreation: setup.MarketCreation{
				InitialMarketProbability:   cfg.Economics.MarketCreation.InitialMarketProbability,
				InitialMarketSubsidization: cfg.Economics.MarketCreation.InitialMarketSubsidization,
				InitialMarketYes:           cfg.Economics.MarketCreation.InitialMarketYes,
				InitialMarketNo:            cfg.Economics.MarketCreation.InitialMarketNo,
				MinimumFutureHours:         cfg.Economics.MarketCreation.MinimumFutureHours,
			},
			MarketIncentives: setup.MarketIncentives{
				CreateMarketCost: cfg.Economics.MarketIncentives.CreateMarketCost,
				TraderBonus:      cfg.Economics.MarketIncentives.TraderBonus,
			},
			User: setup.User{
				InitialAccountBalance: cfg.Economics.User.InitialAccountBalance,
				MaximumDebtAllowed:    cfg.Economics.User.MaximumDebtAllowed,
			},
			Betting: setup.Betting{
				MinimumBet:     cfg.Economics.Betting.MinimumBet,
				MaxDustPerSale: cfg.Economics.Betting.MaxDustPerSale,
				BetFees: setup.BetFees{
					InitialBetFee: cfg.Economics.Betting.BetFees.InitialBetFee,
					BuySharesFee:  cfg.Economics.Betting.BetFees.BuySharesFee,
					SellSharesFee: cfg.Economics.Betting.BetFees.SellSharesFee,
				},
			},
		},
		Frontend: setup.Frontend{
			Charts: setup.FrontendCharts{
				SigFigs: cfg.Frontend.Charts.SigFigs,
			},
		},
	}
}

// ClampChartSigFigs bounds the frontend chart precision to the supported range.
func ClampChartSigFigs(frontend Frontend) int {
	sigFigs := frontend.Charts.SigFigs
	if sigFigs == 0 {
		sigFigs = defaultChartSigFigs
	}

	if sigFigs < minChartSigFigs {
		return minChartSigFigs
	}
	if sigFigs > maxChartSigFigs {
		return maxChartSigFigs
	}
	return sigFigs
}

package adminhandlers

import (
	"encoding/json"
	"fmt"
	"log"
	"math/rand"
	"net/http"
	"socialpredict/handlers"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
	configsvc "socialpredict/internal/service/config"
	"socialpredict/models"
	"socialpredict/security"

	"github.com/brianvoe/gofakeit"
	"gorm.io/gorm"
)

func AddUserHandler(db *gorm.DB, configService configsvc.Service, auth authsvc.Authenticator) func(http.ResponseWriter, *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		responseData, handlerErr := processAddUser(r, db, configService, auth)
		if handlerErr != nil {
			_ = handlers.WriteFailure(w, handlerErr.statusCode, handlerErr.reason)
			if handlerErr.logErr != nil {
				log.Printf("AddUserHandler: %v", handlerErr.logErr)
			}
			return
		}

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(responseData)
	}
}

type handlerError struct {
	message    string
	statusCode int
	logErr     error
	reason     handlers.FailureReason
}

func processAddUser(r *http.Request, db *gorm.DB, configService configsvc.Service, auth authsvc.Authenticator) (map[string]interface{}, *handlerError) {
	securityService := security.NewSecurityService()
	req, decodeErr := decodeAddUserRequest(r)
	if decodeErr != nil {
		return nil, &handlerError{
			message:    decodeErr.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     decodeErr,
			reason:     handlers.ReasonInvalidRequest,
		}
	}

	if err := validateAddUserUsername(securityService, req.Username); err != nil {
		return nil, &handlerError{
			message:    "Invalid username: " + err.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     err,
			reason:     handlers.ReasonValidationFailed,
		}
	}
	req.Username, _ = securityService.Sanitizer.SanitizeUsername(req.Username)

	if db == nil {
		return nil, &handlerError{message: "database unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}

	if auth == nil {
		return nil, &handlerError{message: "authentication service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}
	if _, httpErr := auth.RequireAdmin(r); httpErr != nil {
		return nil, &handlerError{
			message:    httpErr.Message,
			statusCode: httpErr.StatusCode,
			reason:     handlers.AuthFailureReason(httpErr.StatusCode, httpErr.Message),
		}
	}

	if configService == nil {
		return nil, &handlerError{message: "configuration service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}

	appConfig := configService.Current()
	user := buildNewUser(db, req.Username, appConfig)

	if err := checkUniqueFields(db, &user); err != nil {
		return nil, &handlerError{
			message:    err.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     err,
			reason:     handlers.ReasonValidationFailed,
		}
	}

	password, err := generateAndHashPassword(&user)
	if err != nil {
		return nil, &handlerError{
			message:    err.Error(),
			statusCode: http.StatusInternalServerError,
			logErr:     err,
			reason:     handlers.ReasonInternalError,
		}
	}

	if result := db.Create(&user); result.Error != nil {
		return nil, &handlerError{
			message:    "Failed to create user",
			statusCode: http.StatusInternalServerError,
			logErr:     result.Error,
			reason:     handlers.ReasonInternalError,
		}
	}

	responseData := map[string]interface{}{
		"message":  "User created successfully",
		"username": user.Username,
		"password": password,
		"usertype": user.UserType,
	}
	return responseData, nil
}

type addUserRequest struct {
	Username string `json:"username" validate:"required,min=3,max=30,username"`
}

func decodeAddUserRequest(r *http.Request) (addUserRequest, error) {
	var req addUserRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return addUserRequest{}, fmt.Errorf("Error decoding request body")
	}
	return req, nil
}

func validateAddUserUsername(securityService *security.SecurityService, username string) error {
	if err := securityService.Validator.ValidateStruct(addUserRequest{Username: username}); err != nil {
		return err
	}
	_, err := securityService.Sanitizer.SanitizeUsername(username)
	return err
}

func buildNewUser(db *gorm.DB, username string, appConfig *configsvc.AppConfig) models.User {
	return models.User{
		PublicUser: models.PublicUser{
			Username:              username,
			DisplayName:           dusers.UniqueDisplayName(db),
			UserType:              "REGULAR",
			InitialAccountBalance: appConfig.Economics.User.InitialAccountBalance,
			AccountBalance:        appConfig.Economics.User.InitialAccountBalance,
			PersonalEmoji:         randomEmoji(),
		},
		PrivateUser: models.PrivateUser{
			Email:  dusers.UniqueEmail(db),
			APIKey: dusers.GenerateUniqueAPIKey(db),
		},
		MustChangePassword: true,
	}
}

func generateAndHashPassword(user *models.User) (string, error) {
	password := gofakeit.Password(true, true, true, false, false, 12)
	if err := user.HashPassword(password); err != nil {
		return "", fmt.Errorf("Failed to hash password")
	}
	return password, nil
}

func checkUniqueFields(db *gorm.DB, user *models.User) error {
	// Check for existing users with the same username, display name, email, or API key.
	var count int64
	db.Model(&models.User{}).Where(
		"username = ? OR display_name = ? OR email = ? OR api_key = ?",
		user.Username, user.DisplayName, user.Email, user.APIKey,
	).Count(&count)

	if count > 0 {
		return fmt.Errorf("username, display name, email, or API key already in use")
	}

	return nil
}

func randomEmoji() string {
	emojis := []string{"😀", "😃", "😄", "😁", "😆"}
	return emojis[rand.Intn(len(emojis))]
}

package app

import (
	"time"

	"gorm.io/gorm"

	// Domain services
	analytics "socialpredict/internal/domain/analytics"
	dbets "socialpredict/internal/domain/bets"
	dmarkets "socialpredict/internal/domain/markets"
	positionsmath "socialpredict/internal/domain/math/positions"
	"socialpredict/internal/domain/math/probabilities/wpam"
	dusers "socialpredict/internal/domain/users"

	// Repositories
	rbets "socialpredict/internal/repository/bets"
	rmarkets "socialpredict/internal/repository/markets"
	rusers "socialpredict/internal/repository/users"

	// Handlers
	hmarkets "socialpredict/handlers/markets"
	authsvc "socialpredict/internal/service/auth"
	configsvc "socialpredict/internal/service/config"
	"socialpredict/security"
)

// Clock interface for testability
type Clock interface {
	Now() time.Time
}

// SystemClock implements Clock using system time
type SystemClock struct{}

func (SystemClock) Now() time.Time {
	return time.Now()
}

// Container holds all the application dependencies
type Container struct {
	db            *gorm.DB
	configService configsvc.Service
	config        *configsvc.AppConfig
	clock         Clock

	// Repositories
	marketsRepo   rmarkets.GormRepository
	usersRepo     rusers.GormRepository
	analyticsRepo analytics.GormRepository
	betsRepo      rbets.GormRepository

	// Domain services
	analyticsService *analytics.Service
	marketsService   *dmarkets.Service
	usersService     *dusers.Service
	betsService      *dbets.Service
	authService      *authsvc.AuthService

	// Handlers
	marketsHandler *hmarkets.Handler
}

// NewContainer creates a new dependency injection container
func NewContainer(db *gorm.DB, configService configsvc.Service) *Container {
	if configService == nil {
		configService = configsvc.NewStaticService(nil)
	}

	return &Container{
		db:            db,
		configService: configService,
		config:        configService.Current(),
		clock:         SystemClock{},
	}
}

// InitializeRepositories sets up all repository implementations
func (c *Container) InitializeRepositories() {
	c.marketsRepo = *rmarkets.NewGormRepository(c.db)
	c.usersRepo = *rusers.NewGormRepository(c.db)
	c.betsRepo = *rbets.NewGormRepository(c.db)
}

// InitializeServices sets up all domain services with their dependencies
func (c *Container) InitializeServices() {
	// Users service depends on users repository and configuration
	securityService := security.NewSecurityService()

	wpamSeeds := wpam.Seeds{
		InitialProbability:     c.config.Economics.MarketCreation.InitialMarketProbability,
		InitialSubsidization:   c.config.Economics.MarketCreation.InitialMarketSubsidization,
		InitialYesContribution: c.config.Economics.MarketCreation.InitialMarketYes,
		InitialNoContribution:  c.config.Economics.MarketCreation.InitialMarketNo,
	}
	wpamCalculator := wpam.NewProbabilityCalculator(wpam.StaticSeedProvider{Value: wpamSeeds})
	positionProbabilityProvider := positionsmath.NewWPAMProbabilityProvider(wpamCalculator)
	positionCalculator := positionsmath.NewPositionCalculator(
		positionsmath.WithProbabilityProvider(positionProbabilityProvider),
	)

	positionCalcAdapter := analytics.NewMarketPositionCalculator(positionCalculator)
	analyticsConfig := analytics.Config{
		MaximumDebtAllowed: c.config.Economics.User.MaximumDebtAllowed,
		CreateMarketCost:   c.config.Economics.MarketIncentives.CreateMarketCost,
		InitialBetFee:      c.config.Economics.Betting.BetFees.InitialBetFee,
	}
	betsConfig := dbets.Config{
		InitialBetFee:      c.config.Economics.Betting.BetFees.InitialBetFee,
		BuySharesFee:       c.config.Economics.Betting.BetFees.BuySharesFee,
		MaxDustPerSale:     c.config.Economics.Betting.MaxDustPerSale,
		MaximumDebtAllowed: c.config.Economics.User.MaximumDebtAllowed,
	}

	c.analyticsRepo = *analytics.NewGormRepository(c.db, analytics.WithRepositoryPositionCalculator(positionCalcAdapter))
	c.analyticsService = analytics.NewService(&c.analyticsRepo, analyticsConfig, analytics.WithPositionCalculator(positionCalcAdapter))
	c.usersService = dusers.NewService(&c.usersRepo, c.analyticsService, securityService.Sanitizer)
	c.authService = authsvc.NewAuthService(c.usersService)

	// Markets service depends on markets repository and users service
	marketsConfig := dmarkets.Config{
		MinimumFutureHours: c.config.Economics.MarketCreation.MinimumFutureHours,
		CreateMarketCost:   c.config.Economics.MarketIncentives.CreateMarketCost,
		MaximumDebtAllowed: c.config.Economics.User.MaximumDebtAllowed,
	}

	c.marketsService = dmarkets.NewService(
		&c.marketsRepo,
		c.usersService,
		c.clock,
		marketsConfig,
		dmarkets.WithProbabilityEngine(dmarkets.DefaultProbabilityEngine(wpamCalculator)),
	)

	c.betsService = dbets.NewService(&c.betsRepo, c.marketsService, c.usersService, betsConfig, c.clock)
}

// InitializeHandlers sets up all HTTP handlers with their service dependencies
func (c *Container) InitializeHandlers() {
	c.marketsHandler = hmarkets.NewHandler(c.marketsService, c.authService)
}

// Initialize sets up the entire dependency graph
func (c *Container) Initialize() {
	c.InitializeRepositories()
	c.InitializeServices()
	c.InitializeHandlers()
}

// GetMarketsHandler returns the markets HTTP handler
